		}
	}
	fmt.Printf("recv n=%d src=%v ttl=%d rtt=%v reply_type=%d\n", n, src, ttl, rtt, buf[0])
}

func checksum(b []byte) uint16 {
	var s uint32
	for i := 0; i+1 < len(b); i += 2 { s += uint32(b[i])<<8 | uint32(b[i+1]) }
	if len(b)%2 == 1 { s += uint32(b[len(b)-1]) << 8 }
	for s>>16 != 0 { s = s&0xffff + s>>16 }
	return ^uint16(s)
}
