}

func (c *rawConn) Recv(seq uint16, sendTime time.Time, deadline time.Time) (time.Duration, int, string, int, bool) {
	expectedType := byte(0)
	if c.v6 {
		expectedType = 129
	}
	for {
		now := time.Now()
		if !now.Before(deadline) {
			return 0, 0, "", 0, false
		}
		c.pc.SetReadDeadline(deadline)
		buf := make([]byte, 1500)
		n, src, err := c.pc.ReadFrom(buf)
		if err != nil {
			return 0, 0, "", 0, false
		}
		var data []byte
		ttl := 64
		if c.v6 {
			data = buf[:n]
		} else {
			if n < 20 {
				continue
			}
			ihl := int(buf[0]&0x0f) * 4
			if n < ihl+8 {
				continue
			}
			ttl = int(buf[8])
			data = buf[ihl:n]
			n = n - ihl
		}
		if len(data) < 8 || data[0] != expectedType {
			continue
		}
		rseq := uint16(data[6])<<8 | uint16(data[7])
		if rseq != seq {
			continue
		}
		srcIP := ""
		if ia, ok := src.(*net.IPAddr); ok {
			srcIP = ia.IP.String()
		} else {
			srcIP = src.String()
