func parseFlags(args []string) (opts pinguOpts, positionals []string, parseErr error, helpReq bool) {
	opts.count = 20
	i := 0
	for i < len(args) {
		a := args[i]
		if a == "--" {
			positionals = append(positionals, args[i+1:]...)
			return
		}
		if strings.HasPrefix(a, "--") {
			rest := a[2:]
			eqIdx := strings.Index(rest, "=")
			name := rest
			var val string
			hasVal := false
			if eqIdx >= 0 {
				name = rest[:eqIdx]
				val = rest[eqIdx+1:]
				hasVal = true
			}
			switch name {
			case "help":
				if hasVal {
					parseErr = errors.New("bool flag `-h, --help' cannot have an argument")
					return
				}
				helpReq = true
				return
			case "version":
				if hasVal {
					parseErr = errors.New("bool flag `-V, --version' cannot have an argument")
					return
				}
				opts.version = true
			case "privilege":
				if hasVal {
					parseErr = errors.New("bool flag `-P, --privilege' cannot have an argument")
					return
				}
				opts.privilege = true
			case "count":
				if !hasVal {
					if i+1 >= len(args) {
						parseErr = errors.New("expected argument for flag `-c, --count'")
						return
					}
					next := args[i+1]
					if argumentIsOption(next) {
						parseErr = fmt.Errorf("expected argument for flag `-c, --count', but got option `%s'", next)
						return
					}
					val = next
					i++
				}
				v, err := strconv.ParseInt(val, 0, 64)
				if err != nil {
					parseErr = fmt.Errorf("invalid argument for flag `-c, --count' (expected int): %s", err.Error())
					return
				}
				opts.count = v
			default:
				parseErr = fmt.Errorf("unknown flag `%s'", name)
				return
			}
			i++
			continue
		}
		if strings.HasPrefix(a, "-") && len(a) > 1 {
			j := 1
			for j < len(a) {
				ch := a[j]
				switch ch {
				case 'h':
					if j+1 < len(a) && a[j+1] == '=' {
						parseErr = errors.New("bool flag `-h, --help' cannot have an argument")
						return
					}
					helpReq = true
					return
				case 'V':
					if j+1 < len(a) && a[j+1] == '=' {
						parseErr = errors.New("bool flag `-V, --version' cannot have an argument")
						return
					}
					opts.version = true
					j++
				case 'P':
					if j+1 < len(a) && a[j+1] == '=' {
						parseErr = errors.New("bool flag `-P, --privilege' cannot have an argument")
						return
					}
					opts.privilege = true
					j++
				case 'c':
					var val string
					rest := a[j+1:]
					if strings.HasPrefix(rest, "=") {
						val = rest[1:]
					} else if rest != "" {
						val = rest
					} else {
						if i+1 >= len(args) {
							parseErr = errors.New("expected argument for flag `-c, --count'")
							return
						}
						next := args[i+1]
						if argumentIsOption(next) {
							parseErr = fmt.Errorf("expected argument for flag `-c, --count', but got option `%s'", next)
							return
						}
						val = next
						i++
					}
					v, err := strconv.ParseInt(val, 0, 64)
					if err != nil {
						parseErr = fmt.Errorf("invalid argument for flag `-c, --count' (expected int): %s", err.Error())
						return
					}
					opts.count = v
					j = len(a)
				default:
					parseErr = fmt.Errorf("unknown flag `%c'", ch)
					return
				}
			}
			i++
			continue
		}
		positionals = append(positionals, a)
		i++
	}
	return
}

func argumentIsOption(s string) bool {
	if len(s) < 2 || s[0] != '-' {
		return false
	}
	if s[1] == '-' {
		return true
	}
	if s[1] >= '0' && s[1] <= '9' {
		return false
	}
	return true
}

func resolveHost(host string) (*net.IPAddr, error) {
	if len(host) == 0 {
		return nil, errors.New("addr cannot be empty")
	}
	return net.ResolveIPAddr("ip", host)
